INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000001', 'SITE000001', 'BC000001', '2026 봄 시즌 패션 완전 정복', '올봄 반드시 알아야 할 트렌드 아이템과 스타일링 법칙을 총정리했습니다.', '<p>봄이 성큼 다가왔습니다. 올 시즌 패션 트렌드의 핵심 키워드는 <strong>가볍고 자유로움</strong>입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000002', 'SITE000001', 'BC000001', '봄 아우터 베스트 5 완벽 비교', '트렌치코트부터 라이트 재킷까지 올봄 필수 아우터 5가지 심층 비교.', '<p>환절기 필수 아이템, 봄 아우터. 올해는 어떤 아우터를 선택해야 할까요?</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000003', 'SITE000001', 'BC000001', '데님 스타일링 A to Z', '계절별 데님 스타일링 팁과 케어 방법. 기본 아이템 데님 200% 활용법.', '<p>데님은 패션 아이템 중 가장 오래되고, 가장 다양하게 활용할 수 있는 소재입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000004', 'SITE000001', 'BC000001', '미니멀 패션으로 매일 세련되게', '적은 아이템으로 다양한 코디를 완성하는 미니멀 패션의 기술.', '<p>미니멀 패션의 핵심은 <strong>질 좋은 기본 아이템</strong>을 갖추는 것입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000005', 'SITE000001', 'BC000001', '직장인 오피스룩 완성 가이드', '세련된 직장인 스타일, 편하면서도 프로페셔널한 오피스 패션 노하우.', '<p>매일 아침 "오늘 뭐 입지?" 고민하는 직장인들을 위한 스타일 가이드입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000006', 'SITE000001', 'BC000003', '2026 봄 트렌드 컬러 완벽 가이드', '올봄 주목해야 할 트렌드 컬러와 컬러 매칭법. 파스텔부터 비비드까지.', '<p>올 봄·여름 시즌의 핵심 컬러를 소개합니다. Pantone과 각 패션위크 런웨이에서 공통으로 포착된 컬러들입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000007', 'SITE000001', 'BC000003', '패션위크 베스트 룩 분석', '파리, 밀라노, 뉴욕 패션위크 하이라이트 & 2026 F/W 주목 트렌드.', '<p>2026 F/W 시즌 패션위크가 막을 내렸습니다. 런웨이에서 공통으로 보인 키트렌드를 분석합니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000008', 'SITE000001', 'BC000003', 'SNS에서 핫한 스트릿 패션 5가지', '인스타그램·피들·틱톡에서 급부상한 스트릿 패션 트렌드 분석.', '<p>SNS는 이제 패션 트렌드의 발원지입니다. 올해 가장 많이 회자된 스트릿 룩을 정리했습니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000009', 'SITE000001', 'BC000002', '미니멀 라이프를 위한 옷장 정리법', '효율적인 옷장 정리와 캡슐 워드로브 구성. 적은 아이템으로 다양한 코디를.', '<p>미니멀 라이프의 시작은 옷장 정리입니다. 스웨덴의 ''라곰(Lagom)'' 철학처럼 딱 적당한 양이 핵심입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000010', 'SITE000001', 'BC000002', '지속 가능한 패션의 시작', '환경을 생각하는 패션 소비, 어디서부터 시작할 수 있을까요?', '<p>패션 산업은 전 세계 탄소 배출량의 약 10%를 차지합니다. 우리의 소비 습관이 지구에 미치는 영향을 생각해볼 시간입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000011', 'SITE000001', 'BC000002', '패션으로 자존감을 높이는 방법', '내가 입는 옷이 내 기분과 자신감에 미치는 심리학적 영향.', '<p>''Enclothed Cognition(의복된 인지)'' — 입는 옷이 우리의 심리와 행동에 영향을 미친다는 심리학 이론입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000012', 'SITE000001', 'BC000002', '사계절 옷장 관리 완벽 가이드', '계절 전환기마다 현명하게 옷장을 관리하는 실용 가이드.', '<p>옷장 관리를 잘하면 아침 시간이 여유로워집니다. 계절 전환기 옷장 정리 루틴을 공유합니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000013', 'SITE000001', 'BC000004', '체형별 스타일링 완벽 가이드', '내 체형에 맞는 스타일링으로 매일 자신 있게. 체형별 추천 아이템.', '<p>어떤 체형도 스타일링 방법을 알면 매력적으로 표현할 수 있습니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000014', 'SITE000001', 'BC000004', '아이템 하나로 3가지 코디 완성', '트렌치코트 하나로 캐주얼·오피스·데이트 룩 완성하는 다재다능 스타일링.', '<p>한 아이템으로 여러 가지 코디를 만드는 것이 진정한 스타일리스트의 능력입니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000015', 'SITE000001', 'BC000004', '색깔 매칭의 황금 법칙', '컬러 휠을 기반으로 한 과학적인 컬러 매칭 방법과 실용 예시.', '<p>컬러 매칭은 감각만이 아니라 이론적 기반이 있습니다. 컬러 휠의 원리를 알면 누구나 세련된 코디를 할 수 있습니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000016', 'SITE000001', 'BC000005', '패션과 어울리는 봄 메이크업', '봄 패션 트렌드에 맞춘 메이크업 룩. 파스텔 코디에 최적화된 뷰티 팁.', '<p>패션과 메이크업은 서로를 완성합니다. 올봄 트렌드 컬러 파스텔 패션에 어울리는 메이크업을 소개합니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000017', 'SITE000001', 'BC000005', '향수 선택 완벽 가이드', '계절별, 상황별 향수 추천. 나만의 시그니처 향기를 찾는 방법.', '<p>향기는 패션의 마지막 레이어입니다. 나만의 시그니처 향수를 찾으면 스타일이 완성됩니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000018', 'SITE000001', 'BC000006', '여행 패킹의 기술 — 캐리어 하나로 2주', '스마트한 여행 패킹 노하우. 최소한의 짐으로 최대한의 코디.', '<p>여행의 즐거움을 반감시키는 것 중 하나가 무거운 짐입니다. 스마트한 패킹으로 여행을 가볍게 만드세요.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000019', 'SITE000001', 'BC000006', '도시별 드레스코드 완벽 정리', '파리, 도쿄, 뉴욕, 방콕 등 도시별 패션 문화와 여행 스타일링 팁.', '<p>여행지의 문화에 맞는 스타일링은 현지인에 대한 존중입니다. 도시별 드레스코드를 알아봅니다.</p>
INSERT INTO shopjoy_2604.cm_blog (blog_id, site_id, blog_cate_id, blog_title, blog_summary, blog_content, blog_author, prod_id, view_count, use_yn, is_notice, reg_by, reg_date) VALUES ('BL000020', 'SITE000001', 'BC000001', '[공지] ShopJoy 블로그 오픈 안내', 'ShopJoy 공식 블로그가 오픈되었습니다. 패션 트렌드, 스타일링 팁, 이벤트 소식을 전합니다.', '<p>안녕하세요, <strong>ShopJoy</strong>입니다.</p>
